def gen(rng, size):
    n = max(1, min(size, 100))
    base = rng.randint(0, 99)
    arr = [base]
    for _ in range(n - 1):
        if rng.random() < 0.5:
            arr.append(None)
        elif rng.random() < 0.1:
            arr.append(rng.randint(0, 99))
        else:
            arr.append(base)
    return [arr]

