class Solution:
    def isUnivalTree(self, root):
        vals = []
        def dfs(node):
            if node is None:
                return
            vals.append(node.val)
            dfs(node.left)
            dfs(node.right)
        dfs(root)
        return all(v == vals[0] for v in vals)

